import React from "react";
import { Outlet, Link } from "react-router-dom";

const DashboardLayout = () => {
  const user = localStorage.getItem("loggedInUser") || "User";

  const handleLogout = () => {
    localStorage.removeItem("token");
    window.location.href = "/login";
  };

  return (
    <div style={{ display: "flex" }}>

      {/* LEFT SIDEBAR */}
      <div className="sidebar">
        <h2>Vendor Panel</h2>
        <Link to="/dashboard">Dashboard</Link>
        <Link to="/dashboard/profit">Profit</Link>
        <Link to="/dashboard/loss">Loss</Link>
        <Link to="/dashboard/expense">Expense</Link>
        <Link to="/dashboard/analytics">Analytics</Link>
      </div>

      {/* MAIN CONTENT */}
      <div className="main">
        <h1>Welcome, {user}</h1>
        <Outlet />
      </div>

      {/* RIGHT PANEL */}
      <div className="right-panel">

        <div className="profile-card">
          <img src="https://i.pravatar.cc/120" alt="user" />
          <h2>{user}</h2>
          <p>Vendor</p>

          <button className="btn">Edit Profile</button>
          <button className="btn logout" onClick={handleLogout}>
            Logout
          </button>
        </div>

        <div className="profile-details">
          <h3>Profile Info</h3>
          <p><strong>Email:</strong> {user}</p>
          <p><strong>Phone:</strong> +91 9876543210</p>
          <p><strong>Location:</strong> India</p>
        </div>

        <div className="profile-links">
          <h3>Support</h3>
          <p>Help Center</p>
          <p>Contact Us</p>
          <p>Privacy Policy</p>
        </div>

      </div>

    </div>
  );
};

export default DashboardLayout;
